import React from "react";
import { useGame } from "../context/GameContext";

const PnLTable = () => {
  const { state, roomState } = useGame();

  // Add safety checks
  if (!roomState?.gameState?.players) {
    return <div>Loading game state...</div>;
  }

  const players = Object.entries(roomState.gameState.players).map(
    ([id, player]) => ({
      id,
      // Provide default values to prevent undefined errors
      pnl: player?.pnl || 0,
      currentBalance: player?.currentBalance || 0,
      initialBalance: player?.initialBalance || 0,
    })
  );

  return (
    <div className="card">
      <h3 className="section-title">Round P&L</h3>

      {players.length === 0 ? (
        <div className="small">
          Hidden in this round (only personal P&L visible above).
        </div>
      ) : (
        <table className="table">
          <thead>
            <tr>
              <th>Player</th>
              <th>P&L</th>
              <th>Holdings</th>
            </tr>
          </thead>
          <tbody>
            {players.map((player) => (
              <tr key={player.id}>
                <td>{player.id}</td>
                <td
                  className={
                    player.pnl >= 0 ? "profit" : "loss"
                  }
                >
                  {player.pnl >= 0 ? `+${player.pnl}` : player.pnl}
                </td>
                <td className="small">
                  {state.players[player.id].holdings.length}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default PnLTable;
